-- count_genai_total.sql
-- Monthly GenAI article counts WITHOUT governance filter.
-- Divide extract_genai_gov monthly counts by these to get the
-- governance coverage rate (used in the methods validation figure).
-- GENERATED by src/build_query.py — do not hand-edit. Run `python -m src.build_query --write` to refresh.

SELECT
  FORMAT_DATE(
    '%Y-%m',
    PARSE_DATE('%Y%m%d', SUBSTR(CAST(DATE AS STRING), 1, 8))
  ) AS month,

  COUNT(*) AS total_articles

FROM `gdelt-bq.gdeltv2.gkg_partitioned`
WHERE DATE(_PARTITIONTIME) >= '2022-11-01'
  AND DATE(_PARTITIONTIME) <= '2026-06-30'

  -- GenAI filter only — no governance filter.
  AND (
    LOWER(AllNames) LIKE '%chatgpt%'
    OR LOWER(AllNames) LIKE '%generative ai%'
